package my::OneOf;
our @ISA = ('parser::OneOf');
sub cmp_compare {
  my ($self,$other,$ans) = @_;
  foreach $answer (@{$self->{data}}) {
    if ($answer->typeMatch($other)) {
      my $result = $answer->cmp->evaluate($other);
      if ($result->{score}) {
        $ans->score($result->{score});
        $ans->{ans_message} = $result->{ans_message};
        return $ans->{score};
      }
      if ($result->{ans_message}) {
        $ans->{ans_message} = $result->{ans_message}
          if !$ans->{ans_message} || length($ans->{ans_message}) > length($result->{ans_message});
      }
    }
  }
  return 0;
}
package main;
sub OneOfForm {my::OneOf->new(@_)}

Context("Fraction");
Context()->noreduce('(-x)+y','(-x)-y');
do {
  ($h,$k) = random_subset(2, -9..-1, 1..9);
  ($n,$d) = random_coprime([-9..-1],[2..9]);
  $m = Fraction($n/$d);
  $f = Formula("$m*(x - $h) + $k")->reduce;
  $x1 = $h + non_zero_random(-9,9)*$d;
  $y1 = $f->eval(x => $x1);
} until ($y1 != 0);
$g = Formula("$m*(x - $x1) + $y1")->reduce;
$p0 = Point($h,$k);
$p1 = Point($x1,$y1);

Context("Form")->variables->add(y=>'Real');
Context()->noreduce('(-x)+y','(-x)-y');
parser::Assignment->Allow;
$eq=OneOfForm(Formula("y=$f"), Formula("y=$g"));
Context()->flags->set(reduceConstants => 0);
$top = Formula("x - $k");
$top = $top->substitute(x => $y1);
$bottom = Formula("x - $h");
$bottom = $bottom->substitute(x => $x1);

############################################################
# Body
############################################################

BEGIN_PGML
A line passes through two given points. Find an equation for the line in point-slope form using one of the given points.

[`[$p0]`] and [`[$p1]`]

[_]{$eq}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
First we must find this line's slope using the slope formula:

[```\newcommand{\amp}{&}
\begin{aligned}
\amp\frac{y_2-y_1}{x_2-x_1}\\
\amp= \frac{[$top]}{[$bottom]}\\
\amp= \frac{[$top->reduce]}{[$bottom->reduce]}
\end{aligned}
```]

So the slope is [`[$m]\text{.}`] Using the point [`[$p0]`] and point-slope form, an equation for the line is [`y=[$f]\text{.}`]

END_PGML_SOLUTION

